                    return Slidable(
                      key: ValueKey(userId),
                      enabled: !isLocked, // Disable swipe for locked rank #1
                      endActionPane: ActionPane(
                        motion: const BehindMotion(),
                        extentRatio: 0.25,
                        children: [
                          SlidableAction(
                            onPressed: (_) => _unlikeUser(userId),
                            backgroundColor: Colors.redAccent,
